from typing import List


class Solution:
    def countIsolatedIntervals(self, intervals: List[List[int]]) -> int:
        n = len(intervals)
        ans = 0
        for i in range(n):
            s1, e1 = intervals[i]
            isolated = True
            for j in range(n):
                if i == j:
                    continue
                s2, e2 = intervals[j]
                # 标准区间相交判定
                if s1 <= e2 and s2 <= e1:
                    isolated = False
                    break
            if isolated:
                ans += 1
        return ans
```

```java
public class Solution {
    public int countIsolatedIntervals(int[][] intervals) {
        int n = intervals.length;
        int ans = 0;
        for (int i = 0; i < n; i++) {
            int s1 = intervals[i][0], e1 = intervals[i][1];
            boolean isolated = true;
            for (int j = 0; j < n; j++) {
                if (i == j) continue;
                int s2 = intervals[j][0], e2 = intervals[j][1];
                // 标准区间相交判定
                if (s1 <= e2 && s2 <= e1) {
                    isolated = false;
                    break;
                }
            }
            if (isolated) ans++;
        }
        return ans;
    }
}
